// 수정 후 재 검증 함수
scwin.f_ReCheck = async function () {
  if (!scwin.editFlag) {
    $c.gus.cfAlertMsg($p, "값을 수정 후, 재검증 버튼을 눌러주세요.");
    return;
  }
  if (ds_freightList.getRowCount() == 0) {
    $c.gus.cfAlertMsg($p, "먼저 CSV 파일을 업로드해주세요.");
    return;
  }
  ds_csv.removeAll();
  // ds_csv.ImportData(ds_freightList.ExportData(1, ds_freightList.CountRow, true));
  for (var i = 0; i < ds_freightList.getRowCount(); i++) {
    ds_csv.setJSON([ds_freightList.getRowJSON(i)], true);
  }
  ds_freightList.removeAll();
  ds_err.removeAll();
  if (await scwin.f_CsvValidation()) {
    // 값 검증

    scwin.f_ErrCheck(); // 에러 유무 확인
    //tobe 추가
    // gr_freightList.refreshRow(); //색깔 적용 현행화 [그리드 UI만 다시 그려야 할 때 (드문 케이스)]
    ds_freightList.modifyAllStatus("C");
    $c.gus.cfAlertMsg($p, "재검사를 완료하였습니다.");
  }
  scwin.editFlag = false;
};

